</head>
<body>
    <h1>2048</h1>

    <div class="game-container">
        <div class="score-container">
            <div class="score-label">Score</div>
            <div id="score" class="score-value">0</div>
        </div>

        <div class="board-container">
            <div id="board"></div>
        </div>

        <div class="controls">
            <button id="reset">New Game</button>
        </div>
    </div>

    <script>
        // Game state
        let board = [];
        let score = 0;
        const size = 4;

        // Initialize the game
        function initGame() {
            // Create empty board
            board = Array(size).fill().map(() => Array(size).fill(0));

            // Add two random tiles
            addRandomTile();
            addRandomTile();

            score = 0;
            updateScore();
            renderBoard();
        }

        // Add a random tile (2 or 4) to an empty cell
        function addRandomTile() {
            const emptyCells = [];
            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    if (board[r][c] === 0) {
                        emptyCells.push({r, c});
                    }
                }
            }

            if (emptyCells.length > 0) {
                const randomCell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
                board[randomCell.r][randomCell.c] = Math.random() < 0.9 ? 2 : 4;
            }
        }

        // Render the board
        function renderBoard() {
            const boardElement = document.getElementById('board');
            boardElement.innerHTML = '';

            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    const tile = document.createElement('div');
                    tile.className = `tile ${board[r][c] === 0 ? 'empty' : ''}`;

                    if (board[r][c] !== 0) {
                        tile.textContent = board[r][c];
                        tile.setAttribute('data-value', board[r][c]);
                    }

                    boardElement.appendChild(tile);
                }
            }
        }

        // Update the score display
        function updateScore() {
            document.getElementById('score').textContent = score;
        }

        // Slide and merge a single row to the left
        function slideRow(row) {
            // Remove zeros
            let filtered = row.filter(num => num !== 0);

            // Merge adjacent equal numbers
            for (let i = 0; i < filtered.length - 1; i++) {
                if (filtered[i] === filtered[i + 1]) {
                    filtered[i] *= 2;
                    score += filtered[i];
                    filtered[i + 1] = 0;
                    // Skip the next element as it's been merged
                    i++;
                }
            }

            // Remove zeros again after merging
            filtered = filtered.filter(num => num !== 0);

            // Pad with zeros to maintain size
            while (filtered.length < size) {
                filtered.push(0);
            }

            return filtered;
        }

        // Move in a specific direction
        function move(direction) {
            let moved = false;
            const oldBoard = JSON.parse(JSON.stringify(board));

            if (direction === 'left') {
                for (let r = 0; r < size; r++) {
                    board[r] = slideRow(board[r]);
                }
            } else if (direction === 'right') {
                for (let r = 0; r < size; r++) {
                    // Reverse row, slide left, then reverse back
                    let reversed = [...board[r]].reverse();
                    reversed = slideRow(reversed);
                    board[r] = reversed.reverse();
                }
            } else if (direction === 'up') {
                for (let c = 0; c < size; c++) {
                    // Extract column
                    let col = [];
                    for (let r = 0; r < size; r++) {
                        col.push(board[r][c]);
                    }

                    // Slide up (same as slide left)
                    col = slideRow(col);

                    // Put back into board
                    for (let r = 0; r < size; r++) {
                        if (board[r][c] !== col[r]) moved = true;
                        board[r][c] = col[r];
                    }
                }
            } else if (direction === 'down') {
                for (let c = 0; c < size; c++) {
                    // Extract column
                    let col = [];
                    for (let r = 0; r < size; r++) {
                        col.push(board[r][c]);
                    }

                    // Reverse, slide left, reverse back
                    col.reverse();
                    col = slideRow(col);
                    col.reverse();

                    // Put back into board
                    for (let r = 0; r < size; r++) {
                        if (board[r][c] !== col[r]) moved = true;
                        board[r][c] = col[r];
                    }
                }
            }

            // Check if anything changed
            const isSame = JSON.stringify(oldBoard) === JSON.stringify(board);

            // If the board changed, add a new tile and update display
            if (!isSame) {
                addRandomTile();
                renderBoard();
                updateScore();
                return true;
            }

            return false;
        }

        // Set the board directly (for grading)
        function setBoard(arr) {
            board = arr.map(row => [...row]);
            score = 0; // Reset score when setting board
            updateScore();
            renderBoard();
        }

        // Get current board state
        function getBoard() {
            return board.map(row => [...row]);
        }

        // Get current score
        function getScore() {
            return score;
        }

        // Event listeners
        document.addEventListener('keydown', (e) => {
            if (['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown'].includes(e.key)) {
                e.preventDefault();

                let direction = '';
                switch (e.key) {
                    case 'ArrowLeft': direction = 'left'; break;
                    case 'ArrowRight': direction = 'right'; break;
                    case 'ArrowUp': direction = 'up'; break;
                    case 'ArrowDown': direction = 'down'; break;
                }

                move(direction);
            }
        });

        document.getElementById('reset').addEventListener('click', initGame);

        // Expose game API to window
        window.game = {
            size,
            reset: initGame,
            move: (direction) => move(direction),
            board: getBoard,
            setBoard: setBoard,
            score: getScore
        };

        // Initialize the game on load
        initGame();
    </script>
</body>
</html>
